import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { FaArrowLeft, FaMapPin, FaClock, FaCalendar, FaPhone, FaGlobe, FaFacebook, FaEnvelope, FaStar } from 'react-icons/fa';
import { api } from '../api/axios';
import EventCard from '../components/EventCard';

export default function EventDetailNew() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [relatedEvents, setRelatedEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const fetchEventDetails = async () => {
      try {
        const response = await api.get(`/events/${id}/`);
        setEvent(response.data);

        // Fetch related events in the same category - limit to 20
        const relatedResponse = await api.get('/events/', {
          params: { category: response.data.category, limit: 20 }
        });
        setRelatedEvents((relatedResponse.data.results || relatedResponse.data).filter(evt => evt.id !== id));
      } catch (error) {
        console.error('Failed to fetch event:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchEventDetails();
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center" style={{ background: '#191919' }}>
        <p className="text-gray-400">Loading event details...</p>
      </div>
    );
  }

  if (!event) {
    return (
      <div className="min-h-screen flex items-center justify-center" style={{ background: '#191919' }}>
        <p className="text-gray-400">Event not found</p>
      </div>
    );
  }

  const handleCopyLink = () => {
    navigator.clipboard.writeText(window.location.href);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleShare = (platform) => {
    const url = window.location.href;
    const title = event.title;
    if (platform === 'facebook') {
      window.open(`https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(url)}`, '_blank');
    }
  };

  // Parse event image or use placeholder
  const images = event.image
    ? [event.image]
    : ['https://via.placeholder.com/800x600?text=Event+Image'];

  const nextImage = () => {
    setCurrentImageIndex((prev) => (prev + 1) % images.length);
  };

  const prevImage = () => {
    setCurrentImageIndex((prev) => (prev - 1 + images.length) % images.length);
  };

  return (
    <div style={{ background: '#191919' }} className="min-h-screen pb-20">
      {/* Header */}
      <div className="sticky top-0 z-40 flex items-center justify-between px-6 py-4" style={{ borderBottom: '1px solid #2a2a2a' }}>
        <button
          onClick={() => navigate(-1)}
          className="flex items-center gap-2 text-gray-300 hover:text-[#ff00e0] transition-colors"
        >
          <FaArrowLeft /> Back
        </button>
        {event.is_featured && (
          <div className="flex items-center gap-1 px-3 py-1 rounded-full" style={{ background: '#ff00e0', color: '#fff' }}>
            <FaStar size={12} />
            <span className="text-xs font-semibold">FEATURED</span>
          </div>
        )}
      </div>

      {/* Hero Title */}
      <div className="px-6 py-8 max-w-7xl mx-auto">
        <h1 className="text-5xl font-bold text-white mb-4">{event.title}</h1>
        <div className="flex items-center gap-3">
          <span
            style={{ background: '#ff00e0' }}
            className="px-3 py-1 text-xs font-bold text-white rounded-md uppercase"
          >
            {event.category}
          </span>
          <p className="text-gray-400">{event.location}</p>
        </div>
      </div>

      {/* Photo Gallery */}
      <div className="px-6 py-8 max-w-7xl mx-auto">
        <div className="relative rounded-lg overflow-hidden" style={{ background: '#1a1a1a', height: '500px' }}>
          <img
            src={images[currentImageIndex]}
            alt={event.title}
            className="w-full h-full object-cover"
          />
          {images.length > 1 && (
            <>
              <button
                onClick={prevImage}
                className="absolute left-4 top-1/2 transform -translate-y-1/2 bg-black bg-opacity-50 hover:bg-opacity-75 text-white p-3 rounded-full transition-all"
              >
                ←
              </button>
              <button
                onClick={nextImage}
                className="absolute right-4 top-1/2 transform -translate-y-1/2 bg-black bg-opacity-50 hover:bg-opacity-75 text-white p-3 rounded-full transition-all"
              >
                →
              </button>
            </>
          )}
          <div className="absolute bottom-4 left-1/2 transform -translate-x-1/2 flex gap-2">
            {images.map((_, idx) => (
              <button
                key={idx}
                onClick={() => setCurrentImageIndex(idx)}
                className={`w-2 h-2 rounded-full transition-all ${
                  idx === currentImageIndex ? 'bg-[#ff00e0] w-6' : 'bg-gray-600'
                }`}
              />
            ))}
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-8 grid grid-cols-1 lg:grid-cols-3 gap-12">
        {/* Main Content */}
        <div className="lg:col-span-2">
          {/* About Section */}
          <div className="mb-12">
            <h2 className="text-2xl font-bold text-white mb-4">About This Event</h2>
            <p className="text-gray-400 leading-relaxed">{event.description}</p>
          </div>

          {/* Event Details Card */}
          <div
            className="rounded-lg p-8 mb-12"
            style={{ background: '#222222', border: '1px solid #333' }}
          >
            <h3 className="text-xl font-bold text-white mb-6">Event Details</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="flex gap-4">
                <FaCalendar size={24} style={{ color: '#ff00e0' }} />
                <div>
                  <p className="text-gray-500 text-sm">Date</p>
                  <p className="text-white font-semibold">
                    {new Date(event.date).toLocaleDateString('en-US', {
                      weekday: 'long',
                      year: 'numeric',
                      month: 'long',
                      day: 'numeric'
                    })}
                  </p>
                </div>
              </div>
              {event.time && (
                <div className="flex gap-4">
                  <FaClock size={24} style={{ color: '#ff00e0' }} />
                  <div>
                    <p className="text-gray-500 text-sm">Time</p>
                    <p className="text-white font-semibold">{event.time}</p>
                  </div>
                </div>
              )}
              <div className="flex gap-4">
                <FaMapPin size={24} style={{ color: '#ff00e0' }} />
                <div>
                  <p className="text-gray-500 text-sm">Location</p>
                  <p className="text-white font-semibold">{event.location}</p>
                </div>
              </div>
              {event.city && (
                <div className="flex gap-4">
                  <span style={{ color: '#ff00e0' }} className="text-2xl">🏙️</span>
                  <div>
                    <p className="text-gray-500 text-sm">City</p>
                    <p className="text-white font-semibold">{event.city}</p>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Organizer Details */}
          <div
            className="rounded-lg p-8"
            style={{ background: '#222222', border: '1px solid #333' }}
          >
            <h3 className="text-xl font-bold text-white mb-6">Organizer Information</h3>
            <div className="space-y-4">
              <div className="flex gap-4 items-center">
                <span className="text-2xl">👤</span>
                <div>
                  <p className="text-gray-500 text-sm">Organizer</p>
                  <p className="text-white font-semibold">{event.organizer_name || 'N/A'}</p>
                </div>
              </div>
              {event.organizer_email && (
                <div className="flex gap-4 items-center">
                  <FaEnvelope style={{ color: '#ff00e0' }} />
                  <div>
                    <p className="text-gray-500 text-sm">Email</p>
                    <a
                      href={`mailto:${event.organizer_email}`}
                      className="text-[#ff00e0] hover:underline font-semibold"
                    >
                      {event.organizer_email}
                    </a>
                  </div>
                </div>
              )}
              {event.organizer_phone && (
                <div className="flex gap-4 items-center">
                  <FaPhone style={{ color: '#ff00e0' }} />
                  <div>
                    <p className="text-gray-500 text-sm">Phone</p>
                    <a
                      href={`tel:${event.organizer_phone}`}
                      className="text-[#ff00e0] hover:underline font-semibold"
                    >
                      {event.organizer_phone}
                    </a>
                  </div>
                </div>
              )}
              {event.website && (
                <div className="flex gap-4 items-center">
                  <FaGlobe style={{ color: '#ff00e0' }} />
                  <div>
                    <p className="text-gray-500 text-sm">Website</p>
                    <a
                      href={event.website}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="text-[#ff00e0] hover:underline font-semibold truncate"
                    >
                      {event.website}
                    </a>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-1">
          {/* Share Section */}
          <div
            className="rounded-lg p-6 mb-8"
            style={{ background: '#222222', border: '1px solid #333' }}
          >
            <h3 className="text-xl font-bold text-white mb-4">Share This Event</h3>
            <div className="flex gap-3">
              <button
                onClick={() => handleShare('facebook')}
                className="flex items-center justify-center w-12 h-12 rounded-full transition-all hover:scale-110"
                style={{
                  background: 'rgba(255, 0, 224, 0.1)',
                  border: '2px solid #ff00e0',
                  color: '#ff00e0'
                }}
              >
                <FaFacebook size={20} />
              </button>
              <button
                onClick={handleCopyLink}
                className="flex items-center justify-center w-12 h-12 rounded-full transition-all hover:scale-110"
                style={{
                  background: 'rgba(255, 0, 224, 0.1)',
                  border: '2px solid #ff00e0',
                  color: '#ff00e0'
                }}
                title="Copy link to clipboard"
              >
                🔗
              </button>
            </div>
            {copied && <p className="text-green-400 text-xs mt-2">Copied to clipboard!</p>}
          </div>

          {/* Status Badge */}
          <div
            className="rounded-lg p-6 mb-8"
            style={{ background: '#222222', border: '1px solid #333' }}
          >
            <p className="text-gray-500 text-sm mb-2">Status</p>
            <div className="flex items-center gap-2">
              <div
                className="w-3 h-3 rounded-full"
                style={{
                  background:
                    event.status === 'approved'
                      ? '#10b981'
                      : event.status === 'rejected'
                      ? '#ef4444'
                      : '#f59e0b'
                }}
              />
              <p className="text-white font-semibold capitalize">{event.status}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
